func shellOutToCLI(cliPath func() (string, error), commandPath []string) server.ToolHandlerFunc {
	lookupPath, lookupErr := cliPath()
	prefixArgs := append([]string{}, commandPath...)
	return func(ctx context.Context, req mcplib.CallToolRequest) (*mcplib.CallToolResult, error) {
		if lookupErr != nil {
			return mcplib.NewToolResultError(fmt.Sprintf("companion CLI binary not found: %v\nTried sibling lookup, AUTOTEMPEST_CLI_PATH env var, and PATH.", lookupErr)), nil
		}
		args := req.GetArguments()
		finalArgs := append([]string{}, prefixArgs...)
		finalArgs = append(finalArgs, cliArgsFromMCP(args)...)
		if raw, _ := args["args"].(string); strings.TrimSpace(raw) != "" {
			tokens := SplitShellArgs(raw)
			for _, t := range tokens {
				if strings.HasPrefix(t, "-") {
					return mcplib.NewToolResultError(fmt.Sprintf("flag-like argument %q not allowed in positional args field; use structured tool parameters instead", t)), nil
				}
			}
			finalArgs = append(finalArgs, tokens...)
		}
		out, err := RunCLICommand(ctx, lookupPath, finalArgs)
		if err != nil {
			return mcplib.NewToolResultError(err.Error()), nil
		}
		return mcplib.NewToolResultText(out), nil
	}
}

// blockedRootFlags are root-level CLI flags that an MCP client must not be
// able to override via structured tool parameters. Allowing them lets a
// caller swap auth credentials, redirect the API base URL, select a different
// per-client filesystem, load a malicious config file, or change the delivery
// target, all of which sit outside the per-command surface the agent is
// supposed to be calling.
var blockedRootFlags = map[string]bool{
	"args":     true,
	"base-url": true,
	"client":   true,
	"config":   true,
	"deliver":  true,
	"profile":  true,
	"token":    true,
}

func cliArgsFromMCP(args map[string]any) []string {
	keys := make([]string, 0, len(args))
	for k := range args {
		if !blockedRootFlags[k] {
			keys = append(keys, k)
		}
	}
	sort.Strings(keys)

	var out []string
	for _, k := range keys {
		v := args[k]
		switch tv := v.(type) {
		case bool:
			if tv {
				out = append(out, "--"+k)
			}
		case float64:
			out = append(out, "--"+k, strconv.FormatFloat(tv, 'f', -1, 64))
		case string:
			if tv != "" {
				out = append(out, "--"+k, tv)
			}
		case []any:
			if len(tv) > 0 {
				parts := make([]string, 0, len(tv))
				for _, item := range tv {
					parts = append(parts, fmt.Sprintf("%v", item))
				}
				out = append(out, "--"+k, strings.Join(parts, ","))
			}
		default:
			if v != nil {
				out = append(out, "--"+k, fmt.Sprintf("%v", v))
			}
		}
	}
	return out
}

// SplitShellArgs whitespace-splits with shell-style quote preservation.
func SplitShellArgs(s string) []string {
	var tokens []string
	var cur []rune
	inSingleQuote := false
	inDoubleQuote := false
	escaped := false
	for _, r := range s {
		switch {
		case escaped:
			cur = append(cur, r)
			escaped = false
		case r == '\\' && !inSingleQuote:
			escaped = true
		case r == '\'' && !inDoubleQuote:
			inSingleQuote = !inSingleQuote
		case r == '"' && !inSingleQuote:
			inDoubleQuote = !inDoubleQuote
		case (r == ' ' || r == '\t') && !inSingleQuote && !inDoubleQuote:
			if len(cur) > 0 {
				tokens = append(tokens, string(cur))
				cur = cur[:0]
			}
		default:
			cur = append(cur, r)
		}
	}
	if escaped {
		cur = append(cur, '\\')
	}
	if len(cur) > 0 {
		tokens = append(tokens, string(cur))
	}
	return tokens
}

// RunCLICommand executes the companion CLI while preserving stdout as the
// machine-readable channel. Stderr is included only in error text so post-run
// telemetry or quota output cannot corrupt JSON results.
func RunCLICommand(ctx context.Context, binPath string, args []string) (string, error) {
	cmd := exec.CommandContext(ctx, binPath, args...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(stderr.String())
		if msg == "" {
			msg = strings.TrimSpace(stdout.String())
		}
		if msg != "" {
			label := "stderr"
			if strings.TrimSpace(stderr.String()) == "" {
				label = "output"
			}
			return stdout.String(), fmt.Errorf("cli %s: %w (%s: %s)", binPath, err, label, msg)
		}
		return stdout.String(), fmt.Errorf("cli %s: %w", binPath, err)
	}
	return stdout.String(), nil
}
